head.script:
/* Khởi động tải dữ liệu một lần; guard bằng _loaded flag tránh gọi nhiều lần */
scwin._triggerLoad = function () {
    if (scwin._loaded) {
        return;
    }
    scwin._loaded = true;
    scwin._tryLoad(0);
};

/* Fire 4 API submissions; retry tối đa 5 lần nếu submissions chưa sẵn sàng */
scwin._tryLoad = function (attempt) {
    var sbmStats = (typeof sbm_getStats !== "undefined") ? sbm_getStats : $p.getSubmission("sbm_getStats");
    var sbmDist = (typeof sbm_getDistribution !== "undefined") ? sbm_getDistribution : $p.getSubmission("sbm_getDistribution");
    var sbmTrend = (typeof sbm_getStorageTrend !== "undefined") ? sbm_getStorageTrend : $p.getSubmission("sbm_getStorageTrend");
    var sbmRecent = (typeof sbm_getRecentUploads !== "undefined") ? sbm_getRecentUploads : $p.getSubmission("sbm_getRecentUploads");

    if (!sbmStats && !sbmDist && !sbmTrend && !sbmRecent) {
        if (attempt < 5) {
            setTimeout(function () {
                scwin._tryLoad(attempt + 1);
            }, 200);
        }
        return;
    }

    if (window.com && com.sbm && com.sbm.execute) {
        if (sbmStats) com.sbm.execute(sbmStats);
        if (sbmDist) com.sbm.execute(sbmDist);
        if (sbmTrend) com.sbm.execute(sbmTrend);
        if (sbmRecent) com.sbm.execute(sbmRecent);
    } else {
        if (sbmStats) $p.executeSubmission(sbmStats);
        if (sbmDist) $p.executeSubmission(sbmDist);
        if (sbmTrend) $p.executeSubmission(sbmTrend);
        if (sbmRecent) $p.executeSubmission(sbmRecent);
    }
};

scwin.onpageload = scwin._triggerLoad;

setTimeout(function () {
    if (scwin && scwin._triggerLoad) {
        scwin._triggerLoad();
    }
}, 0);

/* Vẽ biểu đồ donut phân bố loại file bằng FusionCharts */
scwin.drawDistributionChart = function(dataList) {
    var totalCnt = 0;
    for (var i = 0; i < dataList.length; i++) {
        totalCnt += Number(dataList[i].CNT);
    }

    var fcData = [];
    for (var i = 0; i < dataList.length; i++) {
        var pct = ((Number(dataList[i].CNT) / totalCnt) * 100).toFixed(1);
        fcData.push({
            "label": dataList[i].FILE_TYPE, 
            "displayValue": dataList[i].FILE_TYPE + "{br}" + pct + "%",
            "value": String(dataList[i].CNT)
        });
    }

    var chartOptions = {
        "showLegend": "1",
        "legendPosition": "bottom",
        "showLabels": "0",
        "showValues": "1",
        "placeValuesInside": "0", 
        "enableSmartLabels": "1",
        "smartLabelClearance": "5",
        "pieRadius": "70",
        "doughnutRadius": "40",
        "chartTopMargin": "0",
        "chartBottomMargin": "0",
        "chartLeftMargin": "0",
        "chartRightMargin": "0",
        "captionPadding": "0",
        "legendPadding": "5",
        "smartLineColor": "#aab1bc",
        "smartLineThickness": "1",
        "legendBorderAlpha": "0",
        "legendShadow": "0",
        "paletteColors": "#66c296,#a1d575,#4e7fcd,#e08d66",
        "baseFontColor": "#1f2733",
        "showBorder": "0",
        "bgColor": "#ffffff",
        "bgAlpha": "0"
    };

    chart_distribution.setChartAttribute(chartOptions);
    chart_distribution.setJSONData({ "data": fcData });
};

/* Vẽ biểu đồ đường xu hướng dung lượng lưu trữ theo tháng */
scwin.drawTrendChart = function(dataList) {
    var fcData = [];
    var maxVal = 0;
    for (var i = 0; i < dataList.length; i++) {
        var val = Number(dataList[i].STORAGE_GB);
        if (!isNaN(val) && val > maxVal) {
            maxVal = val;
        }
        fcData.push({
            "label": dataList[i].MONTH_LABEL,
            "value": String(dataList[i].STORAGE_GB)
        });
    }

    var yMax = maxVal > 0 ? Math.ceil(maxVal * 1.2 * 100) / 100 : 10;

    var chartOptions = {
        "showBorder": "0",
        "bgColor": "#ffffff",
        "bgAlpha": "0",
        "theme": "fusion",
        "showValues": "0",
        "yAxisName": "Storage (GB)",
        "yAxisNameFontSize": "13",
        "yAxisNameFontColor": "#000000",
        "drawAnchors": "1",
        "anchorRadius": "5",
        "anchorBgColor": "#4e7fcd",
        "anchorBorderColor": "#4e7fcd",
        "paletteColors": "#4e7fcd",
        "plotFillAlpha": "20",
        "plotBorderThickness": "3",
        "showAlternateHGridColor": "0",
        "divLineColor": "#e2e8f0",
        "divLineAlpha": "100",
        "divLineThickness": "1",
        "yAxisMinValue": "0",
        "yAxisMaxValue": String(yMax),
        "numDivLines": "3",
        "baseFontColor": "#1f2733",
        "chartTopMargin": "15",
        "chartBottomMargin": "15"
    };

    chart_trend.setChartAttribute(chartOptions);
    chart_trend.setJSONData({ "data": fcData });
};

/* Callback nhận dữ liệu thống kê, cập nhật 3 stat card */
scwin.sbm_getStats_submitdone = function (e) {
    var response = (e && e.responseJSON) ? e.responseJSON : {};
    var body = response.body ? response.body : response;
    var payload = body.dma_stats ? body.dma_stats : {};

    dma_stats.setJSON(payload);
    txt_totalFiles.setLabel(String(payload.TOTAL_FILES || 0));
    txt_totalSizeGb.setLabel(scwin._formatGb(payload.TOTAL_SIZE_GB));
    txt_newUploads.setLabel(String(payload.NEW_UPLOADS_TODAY || 0));
};

/* Callback nhận phân bố file type, vẽ donut chart */
scwin.sbm_getDistribution_submitdone = function (e) {
    var response = (e && e.responseJSON) ? e.responseJSON : {};
    var body = response.body ? response.body : response;
    var rows = body.dlt_distribution ? body.dlt_distribution : [];

    dlt_distribution.setJSON(rows);
    scwin.drawDistributionChart(rows);
};

/* Callback nhận xu hướng storage, vẽ line chart */
scwin.sbm_getStorageTrend_submitdone = function (e) {
    var response = (e && e.responseJSON) ? e.responseJSON : {};
    var body = response.body ? response.body : response;
    var rows = body.dlt_trend ? body.dlt_trend : [];

    dlt_trend.setJSON(rows);
    scwin.drawTrendChart(rows);
};

/* Callback nhận danh sách uploads mới nhất */
scwin.sbm_getRecentUploads_submitdone = function (e) {
    var response = (e && e.responseJSON) ? e.responseJSON : {};
    var body = response.body ? response.body : response;
    var rows = body.dlt_recent ? body.dlt_recent : [];

    scwin._renderRecentUploads(rows);
};

/* Render timeline danh sách uploads vào generator group */
scwin._renderRecentUploads = function (rows) {
    gen_recent.removeAll();

    for (var i = 0; i < rows.length; i++) {
        gen_recent.insertChild(i);
        var fNm = gen_recent.getChild(i, "txt_recFileNm");
        var tAgo = gen_recent.getChild(i, "txt_recUploadDt");
        var iconObj = gen_recent.getChild(i, "img_recentIcon");

        fNm.setLabel(rows[i].FILE_NM || "");
        tAgo.setLabel(rows[i].TIME_AGO || rows[i].UPLOAD_DT || "");

        if (rows[i].STATUS === "PROCESSED" || rows[i].STATUS === "COMPLETED") {
            iconObj.setSrc("data:image/svg+xml;base64,PHN2ZyB4bWxucz0iaHR0cDovL3d3dy53My5vcmcvMjAwMC9zdmciIHZpZXdCb3g9IjAgMCAyNCAyNCIgZmlsbD0ibm9uZSIgc3Ryb2tlPSJibGFjayIgc3Ryb2tlLXdpZHRoPSIzIiBzdHJva2UtbGluZWNhcD0icm91bmQiIHN0cm9rZS1saW5lam9pbj0icm91bmQiPjxwb2x5bGluZSBwb2ludHM9IjIwIDYgOSAxNyA0IDEyIj48L3BvbHlsaW5lPjwvc3ZnPg==");
        } else {
            iconObj.setSrc("/cm/dam/images/ic_document.svg");
        }
    }
};

/* Xử lý lỗi API — silent, WebSquare đã hiển thị thông báo lỗi */
scwin.sbm_submiterror = function () {
};

/* Format số thành chuỗi "X.XX GB" */
scwin._formatGb = function (value) {
    var n = Number(value);
    if (isNaN(n)) {
        n = 0;
    }
    return n.toFixed(2) + " GB";
};

/* Trả về đường dẫn icon SVG tương ứng với loại file */
scwin._getFileIcon = function (fileType) {
    if (fileType === "Images") return "/cm/dam/images/preview/image.svg";
    if (fileType === "Videos") return "/cm/dam/images/preview/video.svg";
    if (fileType === "Audio") return "/cm/dam/images/preview/audio.svg";
    return "/cm/dam/images/preview/document.svg";
};
// Fallback: ensure requests fire even if onpageload is skipped.
setTimeout(function () {
    if (scwin && scwin._triggerLoad) {
        scwin._triggerLoad();
    }
}, 0);
